import java.awt.Color;
import java.awt.Paint;

public class GrayPaintScale implements org.jfree.data.Rangeable {

private double lowerBound;

private double upperBound;

public GrayPaintScale() {}

public void setRange(double lowerBound, double upperBound) {
        this.lowerBound = lowerBound;
        this.upperBound = upperBound;
}

public double getLowerBound(){return lowerBound;}  

public double getUpperBound(){return upperBound;}  

 public synchronized Paint getPaint(double value){
 double v =Math.max(value, this.lowerBound);
 v=Math.min(v,this.upperBound);
 int g =(int)((value - this.lowerBound)/(this.upperBound-this.lowerBound)*255.0);
 return new Color(g,g,g);
 }
}

